import { readFileSync } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";
function phaseLabel(context) {
  return context?.phaseLabel?.trim() || "Phase XX: <Phase Name>";
}
function phasePrefix(context) {
  return context?.phasePrefix?.trim() || "XX";
}
function planId(context) {
  return context?.planId?.trim() || "YY";
}
function reportName(context, fallback) {
  return context?.reportName?.trim() || fallback;
}
function summaryFile(context) {
  return context?.summaryFile?.trim() || `${phasePrefix(context)}-${planId(context)}-SUMMARY.md`;
}
function summaryPath(context) {
  return context?.summaryPath?.trim() || `.blueprint/phases/<phase-dir>/${summaryFile(context)}`;
}
function milestone(context) {
  return context?.milestone?.trim() || "<milestone-version>";
}
function currentPhase(context) {
  return context?.currentPhase?.trim() || "none";
}
function activeCommand(context) {
  return context?.activeCommand?.trim() || "/blu-pause-work";
}
function domain2(context) {
  return context?.domain?.trim() || "<research domain>";
}
function withScaffoldFooter(content) {
  return `${content}

---
*Generated by \`blueprint_artifact_scaffold\`*
`;
}
function cloneJsonObject(value) {
  return JSON.parse(JSON.stringify(value));
}
function readJsonSchemaAsset(schemaFileName) {
  const moduleDir = path.dirname(fileURLToPath(import.meta.url));
  const candidatePaths = [
    path.join(moduleDir, "schemas", schemaFileName),
    path.join(moduleDir, "artifact-contracts", "schemas", schemaFileName)
  ];
  const failures = [];
  for (const candidatePath of candidatePaths) {
    try {
      return JSON.parse(readFileSync(candidatePath, "utf8"));
    } catch (error2) {
      failures.push(
        error2 instanceof Error ? `${candidatePath}: ${error2.message}` : `${candidatePath}: unknown error`
      );
    }
  }
  throw new Error(
    `Could not load artifact model schema asset ${schemaFileName}. Tried: ${failures.join("; ")}`
  );
}
